--- 保卫战, 地图对象

local LxNodeBase = require("LApp.component.LxNodeBase")
---@class LDefenceWarObj:LxNodeBase
local LDefenceWarObj       = LxClass("LDefenceWarObj", LxNodeBase)

local typeofParticleSystem = typeof(UnityEngine.ParticleSystem)
local typeofAnimator       = typeof(UnityEngine.Animator)

local LDefenceWarMoveActor = LXImport("..Actor.LDefenceWarMoveActor")
local LDefenceWarAniActor  = LXImport("..Actor.LDefenceWarAniActor")
local LDefenceWarAtkActor  = LXImport("..Actor.LDefenceWarAtkActor")
local LDefenceWarObjData   = LXImport(".LDefenceWarObjData")
local LBloodStick          = LxRequire("LApp.gameplay.Common.LBloodStick")

local CS                   = CS
local Vector3              = Vector3
local OutPos               = Vector3(10000, 10000, 10000)


-- 一定是1,2,3...
local EnumActors = {
    Move = 1,
    Ani  = 2,
    Atk  = 3,
}

function LDefenceWarObj:LDefenceWarObj(ctrl)
    -- LDefenceWarObjsCtrl
    self._ctrl = ctrl

    self._data = LDefenceWarObjData:New(self)

    self._hitEffObjList = {}
end

-- 销毁
function LDefenceWarObj:Destroy()
    self._data:Destroy()

    for k, v in ipairs(self._actorList) do
        v:Destroy()
    end
    self._actorList = {}

    -- for i, v in ipairs(self._hitEffObjList) do
    --     CS.Destroy(v.obj)
    -- end
    self._hitEffObjList = {}

    if self._bloodStick then
        self._bloodStick:Destroy()
        self._bloodStick = nil
    end

    if self._dpObj then
        self._dpObj:Destroy()
        self._dpObj = nil
    end

    CS.Destroy(self._transform)

    LxNodeBase.Dispose(self)
    self._isDestroy = true
end

-- 销毁
function LDefenceWarObj:IsDestroy()
    return self._isDestroy
end

-- 获取控制器
function LDefenceWarObj:GetCtrl()
    return self._ctrl
end

-- true: 已死亡
function LDefenceWarObj:IsDead()
    if self:IsDestroy() then
        return true
    end
    local hp = self:GetData():GetHp()
    return hp <= 0
end

-- 有效的
function LDefenceWarObj:IsValid()
    if self:IsDead() then
        return false
    end
    return self._init
end

-- 初始化
function LDefenceWarObj:Init(param)
    self._transform = param.trans
    self._index = param.index
    self._data:Init(param.monsterRefId, param.groupRefId, param.pos)
    self._effPoolCtrl = self._ctrl:GetCtrl("EffPool")

    self:InitActor()
    self:InitSpine()
end

-- 设置加载完毕回调
function LDefenceWarObj:SetLoadedCallback(callback)
    self._loadedCallback = callback
end

-- 获取index
function LDefenceWarObj:GetIndex()
    return self._index
end

-- 获取数据
function LDefenceWarObj:GetData()
    return self._data
end

-- 获取transform
function LDefenceWarObj:GetTransform()
    return self._transform
end

-- 初始化表演
function LDefenceWarObj:InitActor()
    self._actorList = {}
    self._actorList[EnumActors.Move] = LDefenceWarMoveActor:New(self)
    self._actorList[EnumActors.Ani] = LDefenceWarAniActor:New(self)
    self._actorList[EnumActors.Atk] = LDefenceWarAtkActor:New(self)
end

-- 获取move actor
function LDefenceWarObj:GetMoveActor()
    return self._actorList[EnumActors.Move]
end

-- 获取move actor
function LDefenceWarObj:GetAniActor()
    return self._actorList[EnumActors.Ani]
end

-- 获取atk actor
function LDefenceWarObj:GetAtkActor()
    return self._actorList[EnumActors.Atk]
end

-- 初始化角色
function LDefenceWarObj:InitSpine()
    local data = self:GetData()

    local parent = CS.FindTrans(self:GetTransform(), "Spine")
    local dp = LDisplaySpine:New()
    self._dpObj = dp
    dp:SetScale(data:GetInitScale())
    dp:CreateSpine(parent, data:GetSpinePrefabName())
    dp:SetLoadedFunction(function()
        self:OnLoadSpineFinish()
    end)
    dp:StartLoad()
end

-- 创建血条
function LDefenceWarObj:CreateBloodStick()
    if not self:GetData():NeedShowBlood() then
        return
    end

    local bloodStick = LBloodStick:New()
    local barType = 1
    local dpTrans = self:GetTransform()
    local topNodePos = self:GetTopNodePos()
    local nowPos = dpTrans.position
    local offPos = topNodePos - nowPos
    offPos.y = offPos.y - 0.05
    bloodStick:CreateBloodStick(barType, 1, 1)
    bloodStick:SetHeroTrans(dpTrans, offPos)
    -- bloodStick:SetVisible(false)
    bloodStick:StartLoad()

    self._bloodStick = bloodStick
    self:ShowBloodStick()
end

-- 显示血条
function LDefenceWarObj:ShowBloodStick()
    if not self._bloodStick then
        return
    end
    local curHp = self:GetData():GetHp()
    local maxHp = self:GetData():GetHpMax()
    local rate = curHp / maxHp
    self._bloodStick:SetHpRate(rate)
end

-- 获取顶点位置
function LDefenceWarObj:GetTopNodePos()
    if not self._topNode then
        local dpTrans = self._dpObj:GetDisplayTrans()
        local topNode = CS.FindTrans(dpTrans, "TopNode")
        self._topNode = topNode
    end
    return self._topNode.position
end

-- 加载spine完成
function LDefenceWarObj:OnLoadSpineFinish()
    if self._loadedCallback then
        self._loadedCallback()
        self._loadedCallback = nil
    end

    local dp = self._dpObj
    if not dp then
        return
    end
    local dpTrans = dp:GetDisplayTrans()
    if not dpTrans then
        return
    end

    dp:SetRenderOrder(-self._index)

    local data = self:GetData()
    local pos = data:GetInitPos()
    self._transform.localPosition = pos
    dp:SetFlipX(pos.x > 0)
    dpTrans.localPosition = Vector3(0, 0, 0)


    local moveActor = self:GetMoveActor()
    moveActor:StartMove()

    local isPause = self._ctrl:GetMgr():IsPause()
    if isPause then
        self:OnPauseGame()
    end
    self._init = true

    self:CreateBloodStick()
end

-- 获取spine对象
function LDefenceWarObj:GetDpObject()
    return self._dpObj
end

-- update
function LDefenceWarObj:Update(dt)
    if self:IsDestroy() then
        return
    end

    if not self._init then
        return
    end

    if self._destroySelfTime then
        self._destroySelfTime = self._destroySelfTime - dt
        if self._destroySelfTime <= 0 then
            self._destroySelfTime = nil
            self:DestroySelf()
            return
        end
    end

    if self._playDeadTime then
        self._playDeadTime = self._playDeadTime - dt
        if self._playDeadTime <= 0 then
            self._playDeadTime = nil
            self:OnDead()
        end
    end

    for k, v in ipairs(self._actorList) do
        v:Update(dt)
    end

    self._data:Update(dt)

    for i, v in ipairs(self._hitEffObjList) do
        v.endTime = v.endTime - dt
        if v.endTime <= 0 then
            CS.Destroy(v.obj)
            table.remove(self._hitEffObjList, i)
            break
        end
    end
end

-- 开始攻击
function LDefenceWarObj:StartAtk()
    self._ctrl:GetMgr():CoreHurt(self)
end

-- 死亡动画
function LDefenceWarObj:PlayDead(delayTime)
    self:UpdateBuff({})
    if delayTime > 0 then
        self._playDeadTime = delayTime
        return
    end
    self:OnDead()
end

-- 死亡
function LDefenceWarObj:OnDead()
    local moveActor = self:GetMoveActor()
    moveActor:StopMove()

    local aniActor = self:GetAniActor()
    aniActor:PlayDie()
end

-- 销毁自己
function LDefenceWarObj:DestroySelf(delayTime)
    if delayTime and delayTime > 0 then
        self._destroySelfTime = delayTime
        return
    end

    local key = self:GetIndex()
    self._ctrl:DestroyObj(key)
end

-- 暂停
function LDefenceWarObj:OnPauseGame()
    for k, v in ipairs(self._actorList) do
        if v.OnPauseGame then
            v:OnPauseGame()
        end
    end
    self:UpdateAnimatorSpeed(0)
end

-- 恢复
function LDefenceWarObj:OnResumeGame()
    for k, v in ipairs(self._actorList) do
        if v.OnResumeGame then
            v:OnResumeGame()
        end
    end

    local speed = self:GetCtrl():GetMgr():GetTimeScale()
    self:UpdateAnimatorSpeed(speed)
end

-- 添加buff
function LDefenceWarObj:AddBuff(data)
    self._data:AddBuff(data)
    self:UpdateBuff()
end

-- 移除buff
function LDefenceWarObj:RemoveBuff(heroId, skillId)
    self._data:RemoveBuff(heroId, skillId)
    self:UpdateBuff()
end

-- 刷新显示buff
function LDefenceWarObj:UpdateBuff(buffList)
    self:InitBuff()
    buffList = buffList or self._data:GetBuffList()
    local num = #buffList
    local posList = self:GetBuffList(num)

    local model = gModelDefenceWar
    for index, data in ipairs(buffList) do
        local trans = self._buffIconList[index]
        if not trans then
            local obj = CS.InstantObject(self._buffIconList[1])
            trans = obj.transform
            trans:SetParent(self._buffIconList[1].parent, false)
            self._buffIconList[index] = trans
        end
        trans.localPosition = posList[index]


        local skillRef = model:GetSkillRef(data.skillId, data.skillLev)
        self:SetSpriteRenderer(trans, skillRef.bufficon)
    end

    for i = num + 1, #self._buffIconList do
        self._buffIconList[i].localPosition = OutPos
    end
end

-- 获取buff位置
function LDefenceWarObj:GetBuffList(num)
    local list = {}
    if num == 0 then
        return list
    end

    if num == 1 then
        list[1] = Vector3(0, 0, 0)
        return list
    end

    -- 宽
    local w = 0.3
    -- 间隔
    local space = 0.05

    local totalW = num * w + (num - 1) * space
    local x = -totalW / 2 + w / 2

    for i = 1, num do
        list[i] = Vector3(x, 0, 0)
        x = x + w + space
    end

    return list
end

-- 初始化buff
function LDefenceWarObj:InitBuff()
    if self._buffIconList then
        return
    end
    self._buffIconList = {}

    local trans = CS.FindTrans(self:GetTransform(), "Buff/Icon")
    self._buffIconList[1] = trans

    local topPos = self:GetTopNodePos()
    topPos.y = topPos.y + 0.2

    -- local scale = self._data:GetInitScale()
    -- local pos = trans.parent.localPosition
    -- pos.y = pos.y + (scale - 1)
    trans.parent.position = topPos
end

-- 受单体技能特效
function LDefenceWarObj:PlayHitEffect(effectName, scale)
    self._effPoolCtrl:LoadEffObj(effectName, function(originObj)
        if self:IsDestroy() then
            return
        end

        local obj = CS.InstantObject(originObj)
        local trans = obj.transform
        trans.localPosition = Vector3(0, 0.5, 0)
        trans.localScale = Vector3(scale, scale, scale)
        local parent = self:GetTransform()
        trans:SetParent(parent, false)

        table.insert(self._hitEffObjList, { obj = obj, trans = trans, endTime = 4 })
    end)
end

-- 设置技能速度
function LDefenceWarObj:UpdateAnimatorSpeed(speed)
    for i, v in ipairs(self._hitEffObjList) do
        local trans = v.trans

        local animatorList = self:GetAnimatorList(trans) or {}
        local animatorLen = #animatorList
        for k = 1, animatorLen do
            local animator = animatorList[k]
            animator.speed = speed
        end

        local particleSystemList = self:GetParticleSystemList(trans) or {}
        local particleSystemLen = #particleSystemList
        for k = 1, particleSystemLen do
            local particleSystem = particleSystemList[k]
            local mainModule = particleSystem.main
            if mainModule then
                mainModule.simulationSpeed = speed
            end
        end
    end
end

-- 获取所有动画
function LDefenceWarObj:GetAnimatorList(trans)
    self._animatorList = self._animatorList or {}
    if not self._animatorList[trans] then
        local cList = trans:GetComponentsInChildren(typeofAnimator, true)
        self._animatorList[trans] = cList:ToTable()
    end
    return self._animatorList[trans]
end

-- 获取所有粒子
function LDefenceWarObj:GetParticleSystemList(trans)
    self._particleSystemList = self._particleSystemList or {}
    if not self._particleSystemList[trans] then
        local cList = trans:GetComponentsInChildren(typeofParticleSystem, true)
        self._particleSystemList[trans] = cList:ToTable()
    end
    return self._particleSystemList[trans]
end

return LDefenceWarObj
